const API_KEY = process.env.REACT_APP_OMDB_API_KEY;
const BASE_URL = "https://omdbapi.com";

export const searchMovies = async (term) => {
    // If the key is missing, handle the error gracefully (Distinction-level handling!)
    if (!API_KEY) {
        console.error("API Key is missing! Check your .env file.");
        return [];
    }

    try {
        const response = await fetch(`${BASE_URL}?s=${term}&apikey=${API_KEY}`);
        const data = await response.json();

        // ADD THIS LINE: Return the specific array OMDb sends back
        return data.Search || [];

    } catch (error) {
        console.error("Fetch error:", error);
        return [];
    }
};
